  }

  function numInput(field: keyof LabelLayout, label: string, unit: 'mm' | '面' = 'mm') {
    const step = unit === 'mm' ? 0.1 : 1
    return (
      <div className="flex items-center gap-2">
        <label className="text-xs text-gray-600 w-20 shrink-0">{label}</label>
